request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?elemName ?owner ?ownerName ?ownerType WHERE {
  ?elem vocab:NamedElement_name ?elemName .
  FILTER(CONTAINS(LCASE(STR(?elemName)), LCASE("APS%20Black%20Box%20Specification%20TMT")))
  ?elem rdf:type ?elemType .
  ?elem vocab:Element_owner* ?owner .
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName . }
  OPTIONAL { ?owner rdf:type ?ownerType . }
}
LIMIT 25
